145	func buildPostAttemptTriagePrompt(ctx context.Context, projectRoot string, b *bead.Bead, report ExecuteBeadReport, reader SessionLogExcerptReader, eventLister interface {
146		Events(id string) ([]bead.BeadEvent, error)
147	}) (string, error) {
148		env := triagePromptEnvelope{
149			Bead: triagePromptBead{
150				ID:           b.ID,
151				Title:        strings.TrimSpace(b.Title),
152				Status:       strings.TrimSpace(b.Status),
153				Priority:     b.Priority,
154				IssueType:    strings.TrimSpace(b.IssueType),
155				Labels:       append([]string(nil), b.Labels...),
156				Parent:       strings.TrimSpace(b.Parent),
157				Description:  strings.TrimSpace(b.Description),
158				Acceptance:   strings.TrimSpace(b.Acceptance),
159				Notes:        strings.TrimSpace(b.Notes),
160				Dependencies: append([]bead.Dependency(nil), b.Dependencies...),
161			},
162			ExecuteBead: report,
163			ProjectRoot: projectRoot,
164		}
165		if len(b.Extra) > 0 {
166			env.Bead.Extra = make(map[string]any, len(b.Extra))
167			for k, v := range b.Extra {
168				if k == "events" || k == "events_attachment" {
169					continue
170				}
171				env.Bead.Extra[k] = v
172			}
173		}
174	
175		if eventLister != nil {
176			events, err := eventLister.Events(b.ID)
177			if err == nil && len(events) > 0 {
178				start := len(events) - maxTriageEventCount
179				if start < 0 {
180					start = 0
181				}
182				env.RecentEvents = make([]bead.BeadEvent, 0, len(events)-start)
183				for _, ev := range events[start:] {
184					env.RecentEvents = append(env.RecentEvents, clampTriageEvent(ev))
185				}
186			}
187		}
188	
189		if report.SessionID != "" && reader != nil {
190			excerpt, err := reader.ReadSessionLogExcerpt(ctx, projectRoot, report.SessionID, defaultSessionLogExcerptBytes)
191			if err == nil && strings.TrimSpace(excerpt) != "" {
192				env.SessionExcerpt = excerpt
193				if path, ok := resolveSessionLogPath(projectRoot, report.SessionID); ok {
194					env.SessionLogPath = path
195				}
196			}
197		}
198	
199		body, err := json.MarshalIndent(env, "", "  ")
200		if err != nil {
201			return "", err
202		}
203	
204		var sb strings.Builder
205		sb.WriteString("MODE: triage\n")
206		sb.WriteString("You are the bead-lifecycle skill (" + postAttemptTriageSkillName + "). Classify the outcome of the attempt and return exactly one JSON object.\n")
207		sb.WriteString("Return structured JSON with the fields classification, recommended_action, rationale, suggested_amendments, suggested_followup_beads.\n")
208		sb.WriteString("Required output shape example: {\"classification\":\"transport\",\"recommended_action\":\"release_claim_retry\",\"rationale\":\"transient provider failure\",\"suggested_amendments\":[],\"suggested_followup_beads\":[]}\n")
209		sb.WriteString("Array fields must be arrays; use [] when none are needed.\n")
210		sb.WriteString("Use only the documented classifications and recommended_action values from the skill contract.\n")
211		sb.WriteString("Do not wrap the answer in markdown or prose.\n\n")
212		sb.WriteString("```json\n")
213		sb.Write(body)
214		sb.WriteString("\n```\n")
215		return sb.String(), nil
216	}
