306	func decodeTriageResult(payload string) TriageResult {
307		var raw triageResultRaw
308		if err := json.Unmarshal([]byte(payload), &raw); err != nil {
309			return malformedTriageResult("json", "invalid JSON object", payload)
310		}
311	
312		out := TriageResult{
313			Classification:    strings.TrimSpace(raw.Classification),
314			RecommendedAction: strings.TrimSpace(raw.RecommendedAction),
315			Rationale:         strings.TrimSpace(raw.Rationale),
316		}
317		out.SuggestedAmendments = []TriageAmendment{}
318		out.SuggestedFollowupBeads = []FollowupBead{}
319	
320		amendments, warnings := decodeTriageAmendments(raw.SuggestedAmendments)
321		out.SuggestedAmendments = amendments
322		out.DecodeWarnings = append(out.DecodeWarnings, warnings...)
323	
324		followups, warnings := decodeTriageFollowupBeads(raw.SuggestedFollowupBeads)
325		out.SuggestedFollowupBeads = followups
326		out.DecodeWarnings = append(out.DecodeWarnings, warnings...)
327	
328		out = normalizeTriageResult(out)
329		out = addTriageRequiredFieldWarnings(out)
330		return out
331	}
