333	func normalizeTriageResult(in TriageResult) TriageResult {
334		in.Classification = strings.TrimSpace(in.Classification)
335		in.RecommendedAction = strings.TrimSpace(in.RecommendedAction)
336		in.Rationale = strings.TrimSpace(in.Rationale)
337		if in.SuggestedAmendments == nil {
338			in.SuggestedAmendments = []TriageAmendment{}
339		}
340		if in.SuggestedFollowupBeads == nil {
341			in.SuggestedFollowupBeads = []FollowupBead{}
342		}
343		if in.Classification != "" && !isRecognizedTriageClassification(in.Classification) {
344			in.DecodeWarnings = appendTriageDecodeWarning(in.DecodeWarnings, newTriageDecodeWarning("classification", "unknown classification", in.Classification))
345		}
346		if in.RecommendedAction != "" && !isRecognizedTriageRecommendedAction(in.RecommendedAction) {
347			in.DecodeWarnings = appendTriageDecodeWarning(in.DecodeWarnings, newTriageDecodeWarning("recommended_action", "unknown recommended_action", in.RecommendedAction))
348		}
349		if len(in.DecodeWarnings) > 0 {
350			in.Malformed = true
351		}
352		return in
353	}
