355	func addTriageRequiredFieldWarnings(in TriageResult) TriageResult {
356		if strings.TrimSpace(in.Classification) == "" {
357			in.DecodeWarnings = appendTriageDecodeWarning(in.DecodeWarnings, newTriageDecodeWarning("classification", "missing classification", ""))
358		}
359		if strings.TrimSpace(in.RecommendedAction) == "" {
360			in.DecodeWarnings = appendTriageDecodeWarning(in.DecodeWarnings, newTriageDecodeWarning("recommended_action", "missing recommended_action", ""))
361		}
362		if len(in.DecodeWarnings) > 0 {
363			in.Malformed = true
364		}
365		return in
