525	func clampTriageEvent(ev bead.BeadEvent) bead.BeadEvent {
526		ev.Summary = truncateBytes(ev.Summary, maxTriageEventBodyBytes)
527		ev.Body = truncateBytes(ev.Body, maxTriageEventBodyBytes)
528		return ev
529	}
