531	func truncateBytes(s string, limit int) string {
532		if limit <= 0 || len(s) <= limit {
533			return s
534		}
535		const markerFmt = "\n…[truncated, %d bytes]\n"
536		marker := fmt.Sprintf(markerFmt, len(s))
537		if len(marker) >= limit {
538			return s[:limit]
539		}
540		head := (limit - len(marker)) / 2
541		tail := limit - len(marker) - head
542		return s[:head] + marker + s[len(s)-tail:]
543	}
