545	func resolveSessionLogPath(projectRoot, sessionID string) (string, bool) {
546		sessionID = strings.TrimSpace(sessionID)
547		if sessionID == "" {
548			return "", false
549		}
550		candidates := []string{sessionID}
551		base := filepath.Base(sessionID)
552		logDir := ResolveLogDir(projectRoot, "")
553		if base != "" {
554			candidates = append(candidates,
555				filepath.Join(logDir, base),
556				filepath.Join(logDir, "agent-"+base),
557				filepath.Join(logDir, "svc-"+base),
558			)
559			if filepath.Ext(base) == "" {
560				candidates = append(candidates,
561					filepath.Join(logDir, "agent-"+base+".jsonl"),
562					filepath.Join(logDir, "svc-"+base+".jsonl"),
563					filepath.Join(logDir, base+".jsonl"),
564				)
565			}
566		}
567		for _, candidate := range candidates {
568			if info, err := os.Stat(candidate); err == nil && !info.IsDir() {
569				return candidate, true
570			}
571		}
572		return "", false
573	}
