36	func (f *CommandFactory) runDocProse(cmd *cobra.Command, args []string) error {
37		changed, _ := cmd.Flags().GetBool("changed")
38	
39		cfg, err := config.LoadWithWorkingDir(f.docRoot())
40		if err != nil {
41			return err
42		}
43	
44		settings, err := docprose.ResolveSettings(cfg)
45		if err != nil {
46			return err
47		}
48	
49		rootDir := f.docRoot()
50		var relPaths []string
51		if changed {
52			if len(args) > 0 {
53				return fmt.Errorf("use either --changed or explicit paths, not both")
54			}
55			relPaths, err = changedMarkdownPaths(rootDir)
56			if err != nil {
57				return err
58			}
59		} else {
60			if len(args) == 0 {
61				return fmt.Errorf("provide one or more paths or pass --changed")
62			}
63			relPaths = append([]string(nil), args...)
64		}
65	
66		type docEntry struct {
67			rel string
68			abs string
69		}
70		var entries []docEntry
71		for _, relPath := range relPaths {
72			cleanRel, absPath, ok := normalizeDocPath(rootDir, relPath)
73			if !ok {
74				continue
75			}
76			if !strings.EqualFold(filepath.Ext(cleanRel), ".md") {
77				continue
78			}
79			if !pathAllowed(cleanRel, settings.Includes, settings.Excludes) {
80				continue
81			}
82			if _, statErr := os.Stat(absPath); statErr != nil {
83				if os.IsNotExist(statErr) {
84					continue
85				}
86				return fmt.Errorf("stat %s: %w", relPath, statErr)
87			}
88			entries = append(entries, docEntry{rel: cleanRel, abs: absPath})
89		}
90	
91		runnerKind := strings.ToLower(strings.TrimSpace(settings.Runner))
92		useEmbedded := runnerKind == "embedded"
93	
94		var findings []docprose.Finding
95		if !useEmbedded && len(entries) > 0 {
96			ctx := cmd.Context()
97			if ctx == nil {
98				ctx = context.Background()
99			}
100			absPaths := make([]string, 0, len(entries))
101			absToRel := make(map[string]string, len(entries))
102			for _, entry := range entries {
103				absPaths = append(absPaths, entry.abs)
104				absToRel[entry.abs] = entry.rel
105			}
106			alerts, valeErr := docprose.NewValeRunner().Findings(ctx, settings, absPaths...)
107			if valeErr != nil {
108				var diag *docprose.ValeDiagnosticError
109				if !errors.As(valeErr, &diag) {
110					return valeErr
111				}
112				fmt.Fprintf(cmd.ErrOrStderr(), "warning: optional prose runner %q is unavailable; using embedded checker\n", "vale")
113				useEmbedded = true
114			} else {
115				normalized := docprose.NormalizeValeAlerts(alerts)
116				for _, finding := range normalized {
117					if rel, ok := absToRel[finding.File]; ok {
118						finding.File = rel
119					}
120					if settings.Severity != "" {
121						finding.Severity = settings.Severity
122					}
123					findings = append(findings, finding)
124				}
125			}
126		}
127	
128		if useEmbedded {
129			checker, checkerErr := docprose.NewChecker(settings.Mode, settings.Vocabulary)
130			if checkerErr != nil {
131				return checkerErr
132			}
133			for _, entry := range entries {
134				content, readErr := os.ReadFile(entry.abs)
135				if readErr != nil {
136					if os.IsNotExist(readErr) {
137						continue
138					}
139					return fmt.Errorf("read %s: %w", entry.rel, readErr)
140				}
141				for _, finding := range checker.Findings(entry.rel, string(content)) {
142					if settings.Severity != "" {
143						finding.Severity = settings.Severity
144					}
145					findings = append(findings, finding)
146				}
147			}
148		}
149	
150		sort.Slice(findings, func(i, j int) bool {
151			if findings[i].File != findings[j].File {
152				return findings[i].File < findings[j].File
153			}
154			if findings[i].Line != findings[j].Line {
155				return findings[i].Line < findings[j].Line
156			}
157			return findings[i].RuleID < findings[j].RuleID
158		})
159	
160		out := cmd.OutOrStdout()
161		if len(findings) == 0 {
162			if changed {
163				fmt.Fprintln(out, "No changed Markdown prose findings.")
164			} else {
165				fmt.Fprintln(out, "No prose findings.")
166			}
167			return nil
168		}
169	
170		for _, finding := range findings {
171			fmt.Fprintf(out, "%s:%d [%s] %s\n", finding.File, finding.Line, finding.Severity, finding.RuleID)
172			fmt.Fprintf(out, "  rationale: %s\n", finding.Rationale)
173			fmt.Fprintf(out, "  suggested edit: %s\n", finding.SuggestedEdit)
174		}
175	
176		if isBlockingProsePolicy(settings.Policy, settings.Severity) {
177			cmd.SilenceUsage = true
178			cmd.SilenceErrors = true
179			return NewExitError(ExitCodeGeneralError, "")
180		}
181		return nil
182	}
183	
184	func isBlockingProsePolicy(policy, severity string) bool {
185		return strings.EqualFold(policy, "blocking") || strings.EqualFold(severity, "blocking")
186	}
