188	func changedMarkdownPaths(rootDir string) ([]string, error) {
189		out, err := internalgit.Command(context.Background(), rootDir, "status", "--porcelain=v1", "--untracked-files=all").Output()
190		if err != nil {
191			return nil, fmt.Errorf("git status failed: %w", err)
192		}
193	
194		var paths []string
195		for _, line := range strings.Split(strings.TrimSpace(string(out)), "\n") {
196			if line == "" || len(line) < 3 {
197				continue
198			}
199			status := line[:2]
200			pathText := strings.TrimSpace(line[3:])
201			if pathText == "" {
202				continue
203			}
204			if strings.Contains(pathText, " -> ") {
205				parts := strings.Split(pathText, " -> ")
206				pathText = parts[len(parts)-1]
207			}
208			if strings.ContainsRune(status, 'D') {
209				continue
210			}
211			if !strings.EqualFold(filepath.Ext(pathText), ".md") {
212				continue
213			}
214			paths = append(paths, filepath.ToSlash(pathText))
215		}
216		sort.Strings(paths)
217		return paths, nil
218	}
