220	func normalizeDocPath(rootDir, input string) (string, string, bool) {
221		if strings.TrimSpace(input) == "" {
222			return "", "", false
223		}
224		absPath := input
225		if !filepath.IsAbs(input) {
226			absPath = filepath.Join(rootDir, input)
227		}
228		absPath = filepath.Clean(absPath)
229		relPath, err := filepath.Rel(rootDir, absPath)
230		if err != nil {
231			relPath = filepath.ToSlash(filepath.Clean(input))
232		} else {
233			relPath = filepath.ToSlash(relPath)
234		}
235		return relPath, absPath, true
236	}
