238	func pathAllowed(relPath string, includes, excludes []string) bool {
239		relPath = filepath.ToSlash(relPath)
240		if len(includes) > 0 && !anyGlobMatch(includes, relPath) {
241			return false
242		}
243		if len(excludes) > 0 && anyGlobMatch(excludes, relPath) {
244			return false
245		}
246		return true
247	}
248	
249	func anyGlobMatch(patterns []string, relPath string) bool {
250		for _, pattern := range patterns {
251			if matchPathGlob(pattern, relPath) {
252				return true
253			}
254		}
255		return false
256	}
257	
258	func matchPathGlob(pattern, name string) bool {
259		pattern = filepath.ToSlash(pattern)
260		name = filepath.ToSlash(name)
261		if matched, _ := filepath.Match(pattern, name); matched {
262			return true
263		}
264		if matched, _ := filepath.Match(pattern, filepath.Base(name)); matched {
265			return true
266		}
267		if !strings.Contains(pattern, "**") {
268			return false
269		}
270		return matchDoubleStar(strings.Split(pattern, "/"), strings.Split(name, "/"))
271	}
272	
273	func matchDoubleStar(patternParts, nameParts []string) bool {
274		if len(patternParts) == 0 {
275			return len(nameParts) == 0
276		}
277		if patternParts[0] == "**" {
278			for i := 0; i <= len(nameParts); i++ {
279				if matchDoubleStar(patternParts[1:], nameParts[i:]) {
280					return true
281				}
282			}
283			return false
284		}
285		if len(nameParts) == 0 {
286			return false
287		}
288		matched, err := filepath.Match(patternParts[0], nameParts[0])
289		if err != nil || !matched {
290			return false
291		}
292		return matchDoubleStar(patternParts[1:], nameParts[1:])
293	}
