323	// runPostAttemptTriage invokes the optional post-attempt triage hook after
324	// the attempt outcome has been finalized but before any cooldown decision is
325	// applied. Hook failures are fail-open: the report is returned unchanged and
326	// legacy cooldown behavior remains in force.
327	func (w *ExecuteBeadWorker) runPostAttemptTriage(ctx context.Context, candidate bead.Bead, report ExecuteBeadReport, runtime ExecuteBeadLoopRuntime, assignee string, now func() time.Time) ExecuteBeadReport {
328		hook := runtime.PostAttemptTriageHook
329		if hook == nil {
330			return report
331		}
332		if isDeterministicSystemOutcomeReason(report.OutcomeReason) {
333			return report
334		}
335		triage, err := hook(ctx, candidate.ID, report)
336		if err != nil {
337			if runtime.Log != nil {
338				_, _ = fmt.Fprintf(runtime.Log, "post-attempt triage error (%s %s): %v (continuing)\n", candidate.ID, report.Status, err)
339			}
340			return report
341		}
342		triage = normalizeTriageResult(triage)
343		hasWarnings := len(triage.DecodeWarnings) > 0 || triage.Malformed
344		classificationRecognized := isRecognizedTriageClassification(triage.Classification)
345		if hasWarnings && runtime.Log != nil {
346			_, _ = fmt.Fprintf(runtime.Log, "post-attempt triage warning (%s %s): %s (continuing)\n", candidate.ID, report.Status, formatTriageWarnings(triage.DecodeWarnings))
347		}
348		if !classificationRecognized && !hasWarnings {
349			return report
350		}
351		if classificationRecognized {
352			report.OutcomeReason = triage.Classification
353		}
354		recordPostAttemptTriageEvent(w.Store, candidate.ID, report, triage, assignee, now().UTC())
355		return report
356	}
