370	// CapLoopCooldown clamps a loop-set cooldown duration to MaxLoopCooldown.
371	// The loop uses this for every SetExecutionCooldown call so no automatic
372	// path can silently park a bead for a year.
373	func CapLoopCooldown(d time.Duration) time.Duration {
374		if d <= 0 {
375			return 0
376		}
377		if d > MaxLoopCooldown {
378			return MaxLoopCooldown
379		}
380		return d
