197	func lintResultPayload(result *Result) (string, error) {
198		if result == nil {
199			return "", &LintHookError{Kind: LintHookErrorKindEmptyOutput, Err: fmt.Errorf("nil result")}
200		}
201		text := strings.TrimSpace(result.CondensedOutput)
202		if text == "" {
203			text = strings.TrimSpace(result.Output)
204		}
205		if text == "" {
206			if strings.TrimSpace(result.Error) != "" {
207				return "", &LintHookError{Kind: LintHookErrorKindDispatchFailure, Err: errors.New(strings.TrimSpace(result.Error))}
208			}
209			if result.ExitCode != 0 {
210				return "", &LintHookError{Kind: LintHookErrorKindDispatchFailure, Err: fmt.Errorf("exit code %d with empty output", result.ExitCode)}
211			}
212			return "", ErrLintHookEmptyOutput
213		}
214		candidate, ok := extractJSONCandidate(text)
215		if !ok {
216			return "", &LintHookError{Kind: LintHookErrorKindBadJSON, Err: fmt.Errorf("no JSON object found")}
217		}
218		return candidate, nil
219	}
