221	func lintPromptCustomFields(extra map[string]any) map[string]any {
222		if len(extra) == 0 {
223			return nil
224		}
225		out := make(map[string]any, len(extra))
226		for k, v := range extra {
227			key := strings.TrimSpace(k)
228			if key == "" || lintPromptSkipCustomField(key) {
229				continue
230			}
231			if val, ok := lintPromptSafeCustomValue(v); ok {
232				out[key] = val
233			}
234		}
235		if len(out) == 0 {
236			return nil
237		}
238		return out
239	}
