241	func lintPromptSkipCustomField(key string) bool {
242		switch key {
243		case "events", "events_attachment", "session_id", "closing_commit_sha":
244			return true
245		}
246		for _, prefix := range []string{"claimed-", "execute-loop-", "cancel-"} {
247			if strings.HasPrefix(key, prefix) {
248				return true
249			}
250		}
251		return false
252	}
253	
254	func lintPromptSafeCustomValue(v any) (any, bool) {
255		switch val := v.(type) {
256		case nil:
257			return nil, true
258		case string:
259			if len(val) > 4096 {
260				return nil, false
261			}
262			return val, true
263		case bool, int, int8, int16, int32, int64, uint, uint8, uint16, uint32, uint64, float32, float64:
264			return val, true
265		case []string:
266			if len(val) > 32 {
267				return nil, false
268			}
269			cp := make([]string, 0, len(val))
270			for _, item := range val {
271				if len(item) > 512 {
272					return nil, false
273				}
274				cp = append(cp, item)
275			}
276			return cp, true
277		case []any:
278			if len(val) > 32 {
279				return nil, false
280			}
281			cp := make([]string, 0, len(val))
282			for _, item := range val {
283				s, ok := item.(string)
284				if !ok || len(s) > 512 {
285					return nil, false
286				}
287				cp = append(cp, s)
288			}
289			return cp, true
290		default:
291			return nil, false
292		}
293	}
